import{c as a,Q as i,j as e,m as l}from"./chunks/framework.iD28w_5a.js";const c=JSON.parse('{"title":"024-shell-1 · Shell","description":"","frontmatter":{"title":"024-shell-1 · Shell"},"headers":[],"relativePath":"tutorial/024-shell-1.md","filePath":"tutorial/024-shell-1.md","lastUpdated":1779686691000}'),n={name:"tutorial/024-shell-1.md"};function t(r,s,p,h,k,d){return i(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="从-syscall-到-shell-上-gdt-重构与-sysretq-的坑" tabindex="-1">从 Syscall 到 Shell（上）：GDT 重构与 SYSRETQ 的坑 <a class="header-anchor" href="#从-syscall-到-shell-上-gdt-重构与-sysretq-的坑" aria-label="Permalink to &quot;从 Syscall 到 Shell（上）：GDT 重构与 SYSRETQ 的坑&quot;">​</a></h1><blockquote><p>标签：x86_64, GDT, SYSCALL, SYSRETQ, STAR MSR, Ring 3 前置：<a href="./023-syscall-3">023 系统调用从 Ring 3 发起</a></p></blockquote><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>说实话，当 shell 第一次在 QEMU 上跑起来并打印出 &quot;cinux&gt; &quot; 提示符的时候，笔者差点从椅子上跳起来——我们终于有了交互式命令行！然而兴奋没持续两秒，紧接着就是一个 #GP 崩溃。修完 #GP，echo 命令又全部失效。这一路踩过的坑，是整个 Cinux 项目到目前为止最令人血压拉满的调试经历。</p><p>本章和后面两章要讲的是 tag 024——从内核侧的 GDT 重构、syscall 路径修复，到用户态 shell REPL 和 Console ANSI 支持。这不是简单的&quot;加个 shell 程序&quot;——在这之前，我们需要先把 syscall 基础设施的几个隐蔽 bug 修干净。</p><h2 id="环境说明" tabindex="-1">环境说明 <a class="header-anchor" href="#环境说明" aria-label="Permalink to &quot;环境说明&quot;">​</a></h2><p>工具链和之前一样：GNU AS (AT&amp;T 语法) + GCC 14 + CMake，QEMU 8.x 作为测试环境。特别注意，本章踩到的 SYSRETQ SS.RPL 问题在真实 Intel 硬件上可能不会复现——这是 QEMU 特定的模拟行为差异。但修复方案（RPL 编码进 STAR 基值）在所有平台上都适用。</p><h2 id="第一步——gdt-重构-为-sysretq-的坑铺路" tabindex="-1">第一步——GDT 重构，为 SYSRETQ 的坑铺路 <a class="header-anchor" href="#第一步——gdt-重构-为-sysretq-的坑铺路" aria-label="Permalink to &quot;第一步——GDT 重构，为 SYSRETQ 的坑铺路&quot;">​</a></h2><h3 id="起因-sysretq-后-ss-不对" tabindex="-1">起因：SYSRETQ 后 SS 不对 <a class="header-anchor" href="#起因-sysretq-后-ss-不对" aria-label="Permalink to &quot;起因：SYSRETQ 后 SS 不对&quot;">​</a></h3><p>shell 启动后，PIT 时钟中断触发了一次 #GP。崩溃日志长这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>==== EXCEPTION: #GP (vector 13) ====</span></span>
<span class="line"><span>  RIP   = 0xFFFFFFFF81000A3C   CS  = 0x0010</span></span>
<span class="line"><span>  ERROR CODE = 0x0000000000000028</span></span>
<span class="line"><span>[FATAL] General Protection Fault in kernel mode (error code=0x0000000028)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>用 addr2line 定位，崩溃点是 irq0_stub 的 iretq 指令。错误码 0x28 = GDT selector index 5（User Data 段），RPL=0。这意味着中断栈帧上的 SS 值是 0x28（RPL=0），而 IRETQ 返回的目标 CPL=3——SS 的 RPL 检查失败。</p><p>但 SYSRETQ 明明应该设置 SS 的 RPL=3 啊？Intel SDM Vol.2A 的 SYSRET 指令参考说得很清楚：&quot;SS is set to (STAR[63:48] + 8) | RPL3&quot;。然而在 QEMU 中，这个 &quot;| RPL3&quot; 并没有生效——SS 被设为 0x20 + 8 = 0x28，少了 RPL=3。</p><p>Wikipedia 的 x86-64 词条明确指出 Intel 和 AMD 在这个行为上的分歧：Intel 硬件无条件设置 RPL=3，AMD 的 RPL 来自 STAR 值。QEMU 在某些版本中两者的行为都没有正确模拟。</p><h3 id="linux-的做法-把-rpl-编码进基值" tabindex="-1">Linux 的做法：把 RPL 编码进基值 <a class="header-anchor" href="#linux-的做法-把-rpl-编码进基值" aria-label="Permalink to &quot;Linux 的做法：把 RPL 编码进基值&quot;">​</a></h3><p>Linux 内核用了一个巧妙的办法规避这个问题——把 RPL=3 直接编码进 STAR[63:48] 的基值。具体来说，STAR[63:48] 不用 0x20，而是用 0x23。这样 SYSRETQ 的加法就变成了：SS = 0x23 + 8 = 0x2B（RPL=3 已包含），CS = 0x23 + 16 = 0x33（同理）。无论硬件是否额外设置 RPL，selector 值都是对的。</p><p>这个修改需要 GDT 布局配合调整。我们需要一个 Linux 兼容的 9 项 GDT——在 Idx 1 留 NULL 占位（TLS），Idx 2-3 是内核代码/数据段，Idx 4-6 是三个用户段（User32 Code、User Data、User64 Code），Idx 7-8 是 TSS。</p><p>selector 常量的变化很大：GDT_KERNEL_CODE 从 0x08 变成 0x10，GDT_USER_CODE 从 0x1B 变成 0x33，GDT_TSS 从 0x28 变成 0x38。由于所有引用都使用 constexpr 常量，改一处自动更新全局。</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">constexpr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint16_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GDT_SYSRET_BASE </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">23</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // RPL=3 baked in</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">constexpr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint16_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GDT_USER_CODE   </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">33</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 0x23 + 16</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">constexpr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint16_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GDT_USER_DATA   </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2B</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 0x23 + 8</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="usermode-s-和-syscall-cpp-的同步更新" tabindex="-1">usermode.S 和 syscall.cpp 的同步更新 <a class="header-anchor" href="#usermode-s-和-syscall-cpp-的同步更新" aria-label="Permalink to &quot;usermode.S 和 syscall.cpp 的同步更新&quot;">​</a></h3><p>STAR MSR 的写入需要在两处同步更新：usermode.S（用立即数加载）和 syscall.cpp（用常量计算）。汇编中把 <code>$0x08</code> 改为 <code>$0x23</code>，<code>$0x08</code> 改为 <code>$0x10</code>。C++ 中把 STAR 值的计算改为 <code>(GDT_SYSRET_BASE &lt;&lt; 48) | (GDT_KERNEL_CODE &lt;&lt; 32)</code>。修复后，回读 STAR 确认 [63:48]=0x23、[47:32]=0x10。</p><h3 id="syscall-init-重构" tabindex="-1">syscall_init 重构 <a class="header-anchor" href="#syscall-init-重构" aria-label="Permalink to &quot;syscall_init 重构&quot;">​</a></h3><p>顺带把 syscall_init() 的接口也重构了——不再需要外部传入 kernel_rsp 参数，改为内部用内联汇编获取。同时在内部注册所有 builtin syscall handlers（sys_read/sys_write/sys_exit/sys_yield），main.cpp 中只需一行调用。</p><h2 id="第二步——syscall-出口-rbx-恢复-让-echo-真正能工作" tabindex="-1">第二步——SYSCALL 出口 RBX 恢复，让 echo 真正能工作 <a class="header-anchor" href="#第二步——syscall-出口-rbx-恢复-让-echo-真正能工作" aria-label="Permalink to &quot;第二步——SYSCALL 出口 RBX 恢复，让 echo 真正能工作&quot;">​</a></h2><p>修完 GDT 和 STAR 后，shell 不再崩溃了。但新的问题出现了——输入 <code>echo hello</code> 按回车，什么也没输出。所有命令都失效了。</p><p>这个 bug 的根因在 syscall.S 的出口路径。之前用 RBX 暂存 syscall 返回值（因为 SYSRETQ 不修改 RBX），但忘了从 trap frame 恢复用户态的原始 RBX。编译器把 shell 的 pos 变量分配到了 RBX（callee-saved 寄存器），每次 sys_read/sys_write 后 RBX 被覆盖为返回值 1，导致所有字符都写到 buffer 的同一个位置。</p><p>修复方法是把返回值暂存从 RBX 改为 gs:16（GS 段的空闲 scratch slot），并新增 <code>movq 80(%rsp), %rbx</code> 从 trap frame 恢复用户 RBX。这个修复只涉及三行汇编的变更，但影响是决定性的——没有它，shell 就是个空壳子。</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    movq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">gs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 返回值存到 scratch（不再用 RBX）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ...</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    movq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 80</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rbx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 从 trap frame 恢复用户 RBX！</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addq </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$96</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsp</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ...</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    movq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">gs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rax</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 从 scratch 恢复返回值</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    swapgs</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sysretq</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这里有一个值得深入讨论的设计对比。Linux 内核的 entry_SYSCALL_64 使用 pt_regs 结构保存了所有通用寄存器，出口路径会完整恢复每一个 callee-saved 寄存器。Cinux 的 trap frame 只 push 了 syscall 必需的寄存器（RDI-RSI-RDX-RCX-RBX-RBP-R12-R13-R14 加上 RSP/RIP/RFLAGS），没有保存 R15。这在当前阶段没问题（内核代码不会用到 R15），但如果将来内核 syscall handler 变得更复杂，需要在入口处补充 R15 的保存。</p><p>xv6 的做法更直接——它用 trapframe 结构在内核栈上保存所有 32 个寄存器，包括所有的 callee-saved 寄存器。这虽然浪费了一点栈空间，但彻底避免了&quot;哪个寄存器忘了保存&quot;的问题。Cinux 选择了一个折中方案——只保存实际会用到的寄存器，既减少 trap frame 大小，又保持代码简洁。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Intel SDM: Vol.2A SYSRET Instruction Reference — CS/SS 计算、RPL 行为 <ul><li>URL: <a href="https://www.felixcloutier.com/x86/sysret" target="_blank" rel="noreferrer">https://www.felixcloutier.com/x86/sysret</a></li></ul></li><li>Wikipedia x86-64: Intel vs AMD SYSRET RPL 行为差异 <ul><li>URL: <a href="https://en.wikipedia.org/wiki/X86-64" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/X86-64</a></li></ul></li><li>Linux kernel entry_64.S: 同样的 RPL 编码技巧 <ul><li>URL: <a href="https://android.googlesource.com/kernel/common/+/refs/heads/android-mainline/arch/x86/entry/entry_64.S" target="_blank" rel="noreferrer">https://android.googlesource.com/kernel/common/+/refs/heads/android-mainline/arch/x86/entry/entry_64.S</a></li></ul></li><li>OSDev Wiki System Calls: SYSCALL/SYSRET 总览 <ul><li>URL: <a href="https://wiki.osdev.org/System_Calls" target="_blank" rel="noreferrer">https://wiki.osdev.org/System_Calls</a></li></ul></li></ul>`,32)])])}const u=a(n,[["render",t]]);export{c as __pageData,u as default};
